    {
      "input": {
        "program": "ints",
        "options": [
          {
            "opts": "positional",
            "type": "vec_int"
          }
        ],
        "positional": [
          "positional"
        ],
        "argv": [
          "--",
          "5",
          "6",
          "-6",
          "0",
          "0xab",
          "0xAf",
          "0x0"
        ],
        "queries": [
          {
            "q": "value",
            "name": "positional",
            "type": "vec_int"
          }
        ]
      },
      "expected_output": "value[positional]=[5,6,-6,0,171,175,0]"
    },
    {
      "input": {
        "program": "ints",
        "options": [
          {
            "opts": "positional",
            "type": "vec_int8"
          }
        ],
        "positional": [
          "positional"
        ],
        "argv": [
          "--",
          "128"
        ],
        "queries": []
      },
      "expected_output": "error=incorrect_argument_type\nparam=128"
    },
    {
      "input": {
        "program": "ints",
        "options": [
          {
            "opts": "positional",
            "type": "vec_uint"
          }
        ],
        "positional": [
          "positional"
        ],
        "argv": [
          "--",
          "-2"
        ],
        "queries": []
      },
      "expected_output": "error=incorrect_argument_type\nparam=-2"
    },
    {
      "input": {
        "program": "floats",
        "options": [
          {
            "opts": "double",
            "type": "double"
