        "argv": [
          "--double",
          "0.5",
          "--",
          "4",
          "-4",
          "1.5e6",
          "-1.5e6"
        ],
        "queries": [
          {
            "q": "value",
            "name": "double",
            "type": "double"
          },
          {
            "q": "value",
            "name": "positional",
            "type": "vec_float"
