    {
      "input": {
        "program": "booleans",
        "options": [
          {
            "opts": "bool",
            "type": "bool"
          },
          {
            "opts": "debug",
            "type": "bool"
          },
          {
            "opts": "timing",
            "type": "bool"
          },
          {
            "opts": "verbose",
            "type": "bool"
