          "--vector",
          "1,-2.1,3,4.5"
        ],
        "queries": [
          {
            "q": "value",
            "name": "vector",
            "type": "vec_double"
          }
        ]
      },
      "expected_output": "value[vector]=[1,-2.1,3,4.5]"
    }
