            "opts": "optional_bool",
            "type": "opt_bool",
            "default": "false"
          }
        ],
        "argv": [
          "--optional",
          "foo",
          "--optional_bool",
          "true"
        ],
        "queries": [
          {
            "q": "value",
            "name": "optional",
            "type": "opt_string"
